settings.custom_css:
.elementor-widget-n-tabs .e-n-tabs-heading {
    backdrop-filter: blur(16px) saturate(180%);
    -webkit-backdrop-filter: blur(16px) saturate(180%);
    background-color: rgba(188, 188, 188, 0.25);
    border-radius: 32px;
    padding: 4px;
}


.elementor-widget-n-tabs .e-n-tabs {
    display: flex; /* Use flexbox to control alignment */
    justify-content: center; /* Horizontally center the tabs */
    align-items: center; /* Vertically align if needed */
    width: 100%; /* Ensure the parent container uses full width */
}
